import{_ as t,o,c as e,ag as n}from"./chunks/framework.eQLvDOR_.js";const u=JSON.parse('{"title":"lean-ai-stack-bootstrapping","description":"","frontmatter":{"title":"lean-ai-stack-bootstrapping","concept":"极简 AI 启动栈","concept_id":"lean-ai-stack-bootstrapping","aliases":["$20-Tech-Stack","Context-Paging"],"sources":["02_Library/AI_IDE_And_CLI/[AI_IDE_And_CLI] How I run 10K MRR on 20 budget.md"],"related_concepts":["[[context-optimization]]","[[notebooklm-rag-orchestration]]"],"created_at":"2026-04-21","last_compiled":"2026-04-21"},"headers":[],"relativePath":"wiki/concepts/lean-ai-stack-bootstrapping.md","filePath":"wiki/concepts/lean-ai-stack-bootstrapping.md","lastUpdated":null}'),i={name:"wiki/concepts/lean-ai-stack-bootstrapping.md"};function r(l,a,s,c,d,g){return o(),e("div",null,[...a[0]||(a[0]=[n('<h1 id="极简-ai-启动栈-lean-ai-stack" tabindex="-1">极简 AI 启动栈 (Lean AI Stack) <a class="header-anchor" href="#极简-ai-启动栈-lean-ai-stack" aria-label="Permalink to &quot;极简 AI 启动栈 (Lean AI Stack)&quot;">​</a></h1><h2 id="设计哲学" tabindex="-1">设计哲学 <a class="header-anchor" href="#设计哲学" aria-label="Permalink to &quot;设计哲学&quot;">​</a></h2><p>由于云服务商（AWS/GCP）倾向于引导用户使用复杂且昂贵的服务，2026 年的独立开发者应回归“极简主义”，将每一分钱花在 AI 推理（Intelligence）而非基础设施（Cloud Bloat）上。</p><h2 id="典型配置-20-40-mo" tabindex="-1">典型配置 ($20-$40/mo) <a class="header-anchor" href="#典型配置-20-40-mo" aria-label="Permalink to &quot;典型配置 ($20-$40/mo)&quot;">​</a></h2><ul><li><strong>服务器</strong>：1GB RAM VPS (Linode/DigitalOcean)。</li><li><strong>语言</strong>：Go (静态编译，部署极简，AI 易读)。</li><li><strong>存储</strong>：SQLite3 + WAL 模式（单文件，零网络跳跃，性能远超远程数据库）。</li><li><strong>推理层</strong>： <ul><li><strong>Local Batch</strong>: 购买二手 GPU (如 3090) 跑 vLLM 做离线研究。</li><li><strong>Frontier API</strong>: 通过 OpenRouter 聚合所有模型。</li></ul></li></ul><h2 id="核心算法-上下文分页-context-paging" tabindex="-1">核心算法：上下文分页 (Context Paging) <a class="header-anchor" href="#核心算法-上下文分页-context-paging" aria-label="Permalink to &quot;核心算法：上下文分页 (Context Paging)&quot;">​</a></h2><p>模仿操作系统的虚存管理。</p><ul><li><strong>SWAP 逻辑</strong>：将对话中次要的、暂时不活跃的信息“交换（Page out）”到外部存储（如嵌入式数据库）。</li><li><strong>Active Window</strong>：仅保留最核心的事实和当前任务锚点在 LLM 的活跃上下文（8K Context）中。</li><li><strong>价值</strong>：极大降低了在处理长周期任务时的平均 Prompt 价格。</li></ul><h2 id="开发技巧" tabindex="-1">开发技巧 <a class="header-anchor" href="#开发技巧" aria-label="Permalink to &quot;开发技巧&quot;">​</a></h2><ul><li><strong>补贴套利</strong>：利用微软等公司的定价模型（如订阅制 Copilot Chat），将超大 context 的修改任务交给能无限追加轮次的工具，“让大厂补贴你的算力成本”。</li></ul><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>DB 配置</strong>：<code>PRAGMA journal_mode=WAL; PRAGMA synchronous=NORMAL;</code> 开启 SQLite 并发潜能。</li><li><strong>Agent 设计</strong>：在 Agent 的 Memory 控制循环中，加入自动分页（Page out）决策逻辑。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/AI_IDE_And_CLI/AI_IDE_And_CLI - How I run 10K MRR on 20 budget.html">[AI_IDE_And_CLI] How I run 10K MRR on 20 budget</a></li></ul>',16)])])}const p=t(i,[["render",r]]);export{u as __pageData,p as default};
